void *
vips__link_map(VipsImage *image, gboolean upstream,
	VipsSListMap2Fn fn, void *a, void *b)
{
	static int serial = 0;

	LinkMap map;
	GSList *images;
	GSList *p;
	void *result;

	images = NULL;

	/* The function might do anything, including removing images
	 * or invalidating other images, so we can't trigger them from within
	 * the image loop. Instead we collect a list of images, ref them,
	 * run the functions, and unref.
	 */

	map.upstream = upstream;
	map.fn = (VipsSListMap2Fn) vips__link_map_cb;
	map.a = (void *) &images;
	map.b = NULL;

	/* We will be walking the tree of images and updating the ->serial
	 * member. There will be intense confusion if two threads try to do
	 * this at the same time.
	 */
	g_mutex_lock(vips__global_lock);

	serial += 1;
	map.serial = serial;

	vips__link_mapp(image, &map, NULL);

	for (p = images; p; p = p->next)
		g_object_ref(p->data);

	g_mutex_unlock(vips__global_lock);

	result = vips_slist_map2(images, fn, a, b);

	for (p = images; p; p = p->next)
		g_object_unref(p->data);
	g_slist_free(images);

	return result;
}

static int
vips_thumbnail_find_jpegshrink(VipsThumbnail *thumbnail,
	int width, int height)
{
	double shrink = vips_thumbnail_calculate_common_shrink(thumbnail,
		width, height);

	/* We can't use pre-shrunk images in linear mode. libjpeg shrinks in Y
	 * (of YCbCR), not linear space.
	 */
	if (thumbnail->linear)
		return 1;

	/* Shrink-on-load is a simple block shrink and will add quite a bit of
	 * extra sharpness to the image. We want to block shrink to a
	 * bit above our target, then vips_shrink() / vips_reduce() to the
	 * final size.
	 *
	 * Leave at least a factor of two for the final resize step.
	 */
	if (shrink >= 16)
		return 8;
	else if (shrink >= 8)
		return 4;
	else if (shrink >= 4)
		return 2;
	else
		return 1;
}

