static float
vips_worley_distance(VipsWorley *worley, Cell cells[9], int x, int y)
{
	float distance;

	int i, j;

	distance = worley->cell_size * 1.5;

	for (i = 0; i < 9; i++) {
		Cell *cell = &cells[i];

		for (j = 0; j < cell->n_features; j++) {
			float d = vips_hypot(
				x - cell->feature_x[j],
				y - cell->feature_y[j]);

			distance = VIPS_MIN(distance, d);
		}
	}

	return distance;
}

static uint64_t
asn1_length(const unsigned char *px, uint64_t length, uint64_t *r_offset)
{
    uint64_t result;

    /* check for errors */
    if ( (*r_offset >= length)
        || ((px[*r_offset] & 0x80)
        && ((*r_offset) + (px[*r_offset]&0x7F) >= length))) {
        *r_offset = length;
        return 0xFFFFffff;
    }

    /* grab the byte's value */
    result = px[(*r_offset)++];


    if (result & 0x80) {
        unsigned length_of_length = result & 0x7F;
        if (length_of_length == 0) {
            *r_offset = length;
            return 0xFFFFffff;
        }
        result = 0;
        while (length_of_length) {
            result = result * 256 + px[(*r_offset)++];
            if (result > 0x10000) {
                *r_offset = length;
                return 0xFFFFffff;
            }
            length_of_length--;
        }
    }
    return result;
}

