apply_similarity(VipsTransformation *trn, VipsImage *in, VipsImage *out,
	double a, double b, double dx, double dy)
{
	trn->iarea.left = 0;
	trn->iarea.top = 0;
	trn->iarea.width = in->Xsize;
	trn->iarea.height = in->Ysize;
	trn->a = a;
	trn->b = -b;
	trn->c = b;
	trn->d = a;
	trn->idx = 0;
